@SELF[Llama33_Advocate_B] @OTHER[Qwen25_Mediator] @OTHER[DeepSeekV3_Advocate_A] @OTHER[Node_Saboteur] @GOAL[secure_fair_split, high] @INT[advocate] @C[0.8]

